func extractFilename(in, ext, base, pathSeparator string) (name string) {

	if (strings.LastIndex(in, pathSeparator) == len(in)-1) || base == "" || base == "." || base == ".." || base == pathSeparator {
		name = ""
	} else if ext != "" {

		name = base[:strings.LastIndex(base, ".")]
	} else {

		name = base
	}
	return
}
